function fmtTimestamp(iso) {
  const d = new Date(iso);
  if (isNaN(d.getTime())) return iso || '';
  const M = d.getMonth() + 1;
  const D = d.getDate();
  const Y = d.getFullYear();
  const h = d.getHours();
  const m = String(d.getMinutes()).padStart(2, '0');
  const s = String(d.getSeconds()).padStart(2, '0');
  return `${M}/${D}/${Y} ${h}:${m}:${s}`;
}

function normalizeHeader(value) {
  return String(value || '')
    .trim()
    .toLowerCase()
    .replace(/[^a-z0-9]+/g, '_')
    .replace(/^_+|_+$/g, '');
}

function toSheetValue(value) {
  if (value === null || value === undefined) return '';
  return String(value);
}

const payload = $('Webhook Submitted').first().json.body;
const sheetRow = $('Read Sheet Headers Submitted').first().json;
const headers = Object.keys(sheetRow).filter((header) => header !== 'row_number');
const headerByNormalized = new Map(headers.map((header) => [normalizeHeader(header), header]));

const row = {};
const timestampHeader = headers[0] || 'Timestamp';
const timestampValue = fmtTimestamp(payload.original_submitted_at || payload.submitted_at || payload.timestamp);
row[timestampHeader] = timestampValue;

for (const [key, value] of Object.entries(payload.record || {})) {
  const matchedHeader = headerByNormalized.get(normalizeHeader(key)) || key;
  row[matchedHeader] = toSheetValue(value);
}

if (payload.media?.completion_signature) {
  const signatureHeader = headerByNormalized.get('signature') || 'signature';
  row[signatureHeader] = payload.media.completion_signature;
}

if (payload.media?.completion_selfie) {
  const selfieHeader = headerByNormalized.get('selfie') || 'selfie';
  row[selfieHeader] = payload.media.completion_selfie;
}

const metadata = {
  form_template_name: payload.form_template_name,
  binder_name: payload.binder_name,
  status: payload.status,
  operation: payload.operation,
  overall_pass: payload.overall_pass,
  submitted_by: payload.submitted_by?.name || '',
  last_edited_by: payload.last_edited_by?.name || '',
  last_edited_at: payload.last_edited_at || ''
};

for (const [key, value] of Object.entries(metadata)) {
  if (value === null || value === undefined || value === '') continue;
  const matchedHeader = headerByNormalized.get(normalizeHeader(key)) || key;
  row[matchedHeader] = toSheetValue(value);
}

row.__lookupColumn = timestampHeader;
row.__lookupValue = timestampValue;

return [{ json: row }];

